staticData.activeRecordingTimeOfDay = timeOfDay;
delete staticData.activeRecording;

return [{
  json: {
    scenarioName,
    scenarioRecordId,
    chatId: input.chatId,
    clipCount,
    timeOfDay,
    ledColor: '',
    timeLabel: 'ï? Day',
    message: '... ' + clipCount + ' clip " ï? Day " salvate per "' + formatName(scenarioName) + '".\n\n?³ Generando hook image...',
  }
}];

// NODE: Process Hook Trim
// Receives timestamps from parse-video-message (messageType: 'hook_trim')
// Looks up phone from chatId, finds the matching queue record, trims clips, sends to Telegram, saves to Hook Pool
// Mode: Run Once for All Items

const fs = require('fs');
const { execSync } = require('child_process');
const { URL } = require('url');
const _https = require('https');
const _http = require('http');

// ─── Polyfill fetch for n8n sandbox ───
async function fetch(url, opts) {
  return new Promise((resolve, reject) => {
    const u = new URL(url);
    const mod = u.protocol === 'https:' ? _https : _http;
    const req = mod.request(url, {
      method: (opts && opts.method) || 'GET',
      headers: (opts && opts.headers) || {},
    }, (res) => {
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => {
        const buf = Buffer.concat(chunks);
        resolve({
          ok: res.statusCode >= 200 && res.statusCode < 300,
          status: res.statusCode,
          text: () => Promise.resolve(buf.toString()),
          json: () => Promise.resolve(JSON.parse(buf.toString())),
          arrayBuffer: () => Promise.resolve(buf.buffer.slice(buf.byteOffset, buf.byteOffset + buf.byteLength)),
        });
      });
    });
    req.on('error', reject);
    if (opts && opts.body) req.write(typeof opts.body === 'string' ? opts.body : opts.body);
    req.end();
  });
}

const input = $input.first().json;
const timestamps = input.timestamps; // array of numbers and 'x'
const chatId = input.chatId;

const ABASE = 'appsgjIdkpak2kaXq';
const QUEUE_TABLE = 'tblXpyxSLN2vSJ4i3';
const POOL_TABLE = 'tbl3q91o3l0isSX9w';
const PHONES_TABLE = 'tblCvT47GpZv29jz9';
const ATOKEN = $env.AIRTABLE_API_KEY || '';
const AT = 'https://api.airtable.com/v0/' + ABASE;
const AH = { 'Authorization': 'Bearer ' + ATOKEN, 'Content-Type': 'application/json' };
const TBOT = $env.TELEGRAM_BOT_TOKEN || '';

const log = [];

// ─── Look up phone from chatId ───
const phonesRes = await fetch(
  AT + '/' + PHONES_TABLE + '?filterByFormula=' + encodeURIComponent("{telegram_chat_id}='" + chatId + "'") + '&maxRecords=1',
  { headers: AH }
);
let phoneId = '';
if (phonesRes.ok) {
  const phoneRecs = (await phonesRes.json()).records || [];
  if (phoneRecs.length > 0) {
    phoneId = phoneRecs[0].fields.phone_id || '';
    log.push('Phone: ' + phoneId + ' (chat ' + chatId + ')');
  }
}

// ─── Find the video_review_sent record for this phone ───
let filter = "{status}='video_review_sent'";
if (phoneId) {
  filter = "AND({status}='video_review_sent',{phone_id}='" + phoneId + "')";
}
const qRes = await fetch(
  AT + '/' + QUEUE_TABLE + '?filterByFormula=' + encodeURIComponent(filter) + '&maxRecords=1',
  { headers: AH }
);
if (!qRes.ok) {
  log.push('Queue query failed: ' + qRes.status);
  return [{ json: { status: 'error', log } }];
}
const records = (await qRes.json()).records || [];
if (records.length === 0) {
  log.push('No video_review_sent record found' + (phoneId ? ' for ' + phoneId : ''));
  return [{ json: { status: 'no_review', log } }];
}

const rec = records[0];
const f = rec.fields;
const hookTexts = JSON.parse(f.hook_texts_json || '[]');
const scenarioIds = JSON.parse(f.scenario_ids_json || '[]');

log.push('Trimming ' + rec.id + ' with timestamps: ' + timestamps.map(v => v === 'x' ? 'skip' : v).join(', '));

// Download video
const vidRes = await fetch(f.video_url);
if (!vidRes.ok) {
  log.push('Video download failed: ' + vidRes.status);
  await fetch(AT + '/' + QUEUE_TABLE, {
    method: 'PATCH', headers: AH,
    body: JSON.stringify({ records: [{ id: rec.id, fields: { status: 'failed', error_message: 'Video download failed' } }] }),
  });
  return [{ json: { status: 'error', log } }];
}
const vidBuf = Buffer.from(await vidRes.arrayBuffer());
const rawPath = '/tmp/trim_' + Date.now() + '.mp4';
fs.writeFileSync(rawPath, vidBuf);
log.push('Video downloaded: ' + vidBuf.length + ' bytes');

// Trim clips — send to the SAME chat the user sent timestamps from
const targetChat = chatId || '5120450288';

let clipsSaved = 0;
for (let i = 0; i < timestamps.length; i++) {
  const start = timestamps[i];
  if (start === 'x') {
    log.push('Clip ' + (i + 1) + ' skipped');
    continue;
  }
  const clipPath = '/tmp/clip_' + Date.now() + '_' + i + '.mp4';
  try {
    execSync(
      'ffmpeg -y -ss ' + start + ' -i "' + rawPath + '" -t 3 -c copy "' + clipPath + '"',
      { timeout: 15000 }
    );

    // Send clip to Telegram (same chat as the phone)
    const clipBuf = fs.readFileSync(clipPath);
    const boundary = '----Clip' + Date.now() + i;
    const caption = 'Clip ' + (i + 1) + '/' + timestamps.length + ' [' + start + 's-' + (start + 3) + 's] — ' + (hookTexts[i] || '');
    const header =
      '--' + boundary + '\r\nContent-Disposition: form-data; name="chat_id"\r\n\r\n' + targetChat + '\r\n' +
      '--' + boundary + '\r\nContent-Disposition: form-data; name="caption"\r\n\r\n' + caption + '\r\n' +
      '--' + boundary + '\r\nContent-Disposition: form-data; name="video"; filename="clip.mp4"\r\nContent-Type: video/mp4\r\n\r\n';
    const body = Buffer.concat([Buffer.from(header), clipBuf, Buffer.from('\r\n--' + boundary + '--\r\n')]);
    await fetch('https://api.telegram.org/bot' + TBOT + '/sendVideo', {
      method: 'POST',
      headers: { 'Content-Type': 'multipart/form-data; boundary=' + boundary },
      body,
    });

    // Save to Hook Pool
    await fetch(AT + '/' + POOL_TABLE, {
      method: 'POST', headers: AH,
      body: JSON.stringify({ records: [{ fields: {
        hook_text: hookTexts[i] || '',
        hook_type: f.hook_mode || 'speaking',
        phone_id: f.phone_id || '',
        concept_id: f.concept_id || '',
        scenario_id: scenarioIds[i] || '',
        source_video_url: f.video_url,
        clip_start_sec: start,
        clip_duration_sec: 3,
        time_of_day: f.time_of_day || 'night',
        status: 'ready',
        created_at: new Date().toISOString(),
      } }] }),
    });
    clipsSaved++;
    log.push('Clip ' + (i + 1) + ' saved at ' + start + 's');
    try { fs.unlinkSync(clipPath); } catch (e) {}
  } catch (e) {
    log.push('Clip ' + (i + 1) + ' failed: ' + e.message);
  }
}

try { fs.unlinkSync(rawPath); } catch (e) {}

// Update queue record
await fetch(AT + '/' + QUEUE_TABLE, {
  method: 'PATCH', headers: AH,
  body: JSON.stringify({ records: [{ id: rec.id, fields: { status: 'clips_saved', clips_count: clipsSaved } }] }),
});

// Send confirmation to the same chat
await fetch('https://api.telegram.org/bot' + TBOT + '/sendMessage', {
  method: 'POST',
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify({ chat_id: targetChat, text: '✅ ' + clipsSaved + ' clips saved to Hook Pool' }),
});

log.push('Done: ' + clipsSaved + ' clips saved');
return [{ json: { status: 'ok', clipsSaved, phoneId, log } }];

// NODE: Auto Produce (Schedule Trigger -- quota check + dispatch via webhook)
// Runs every 30 min. For each phone needing content, triggers a separate
// production execution via internal webhook (true parallelism).
//
// WIRING: Auto Produce Schedule -> this Code node

// --- fetch polyfill (n8n Code node sandbox lacks global fetch) ---
const _https = require('https');
const _http = require('http');
const { URL } = require('url');
function fetch(url, opts = {}, _redirectCount = 0) {
  return new Promise((resolve, reject) => {
    if (_redirectCount > 5) return reject(new Error('Too many redirects'));
    const u = new URL(url);
    const lib = u.protocol === 'https:' ? _https : _http;
    const body = opts.body || null;
    const ro = {
      hostname: u.hostname, port: u.port || undefined,
      path: u.pathname + u.search, method: opts.method || 'GET',
      headers: { ...(opts.headers || {}) },
    };
    if (body && !ro.headers['Content-Length']) {
      ro.headers['Content-Length'] = Buffer.byteLength(body);
    }
    const req = lib.request(ro, (res) => {
      if ([301, 302, 307, 308].includes(res.statusCode) && res.headers.location) {
        return fetch(res.headers.location, opts, _redirectCount + 1).then(resolve, reject);
      }
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => {
        const buf = Buffer.concat(chunks);
        resolve({
          ok: res.statusCode >= 200 && res.statusCode < 300,
          status: res.statusCode,
          text: () => Promise.resolve(buf.toString()),
          json: () => Promise.resolve(JSON.parse(buf.toString())),
        });
      });
    });
    req.on('error', reject);
    if (body) req.write(body);
    req.end();
  });
}

const AIRTABLE_BASE = 'https://api.airtable.com/v0/appsgjIdkpak2kaXq';
const ATOKEN = (typeof $env !== 'undefined' && $env.AIRTABLE_API_KEY) || '';
const PHONES_TABLE = 'tblCvT47GpZv29jz9';
const CONTENT_LIBRARY_TABLE = 'tblx1KX7mlTX5QyGb';
const VIDEO_RUNS_TABLE = 'tbltCYcVXrLYvyIJL';
const SCENARIOS_TABLE = 'tblcQaMBBPcOAy0NF';

// Buffer: produce enough videos to cover this many days per phone
const BUFFER_DAYS = 7;

// Internal n8n webhook (runs inside same container on port 5678)
const WEBHOOK_BASE = (typeof $env !== 'undefined' && $env.N8N_WEBHOOK_URL)
  || 'http://localhost:5678';
const WEBHOOK_PATH = '/webhook/auto-produce';

async function airtableGet(tableId, params = {}) {
  const qs = Object.entries(params)
    .map(([k, v]) => encodeURIComponent(k) + '=' + encodeURIComponent(v))
    .join('&');
  const url = AIRTABLE_BASE + '/' + tableId + (qs ? '?' + qs : '');
  const res = await fetch(url, { headers: { 'Authorization': 'Bearer ' + ATOKEN } });
  if (!res.ok) throw new Error('Airtable ' + res.status + ': ' + (await res.text()));
  return res.json();
}

// --- 1. Load active phones ---
const phonesData = await airtableGet(PHONES_TABLE, {
  filterByFormula: "{is_active}=TRUE()",
});
const phones = (phonesData.records || []).map(r => ({
  recordId: r.id,
  chatId: r.fields.telegram_chat_id || '',
  phoneName: r.fields.phone_name || '',
  phoneId: r.fields.phone_id || '',
  videosPerDay: r.fields.videos_per_day || 2,
}));

if (phones.length === 0) {
  console.log('[auto-produce] No active phones found');
  return [{ json: { triggered: 0, log: ['No active phones'], timestamp: new Date().toISOString() } }];
}

const log = [];
let triggered = 0;

for (const phone of phones) {
  if (!phone.chatId) {
    log.push(phone.phoneName + ': skip (no chatId)');
    continue;
  }

  // --- 2. Check for active Video Runs (status = 'started') ---
  try {
    const runsData = await airtableGet(VIDEO_RUNS_TABLE, {
      filterByFormula: "AND({telegram_chat_id}='" + phone.chatId + "', {status}='started')",
      maxRecords: '1',
      'fields[]': 'status',
    });
    if ((runsData.records || []).length > 0) {
      log.push(phone.phoneName + ': skip (production in progress)');
      continue;
    }
  } catch (e) {
    log.push(phone.phoneName + ': skip (runs check error: ' + e.message + ')');
    continue;
  }

  // --- 3. Count pending videos in Content Library ---
  const targetPending = phone.videosPerDay * BUFFER_DAYS;
  let pendingCount = 0;
  try {
    const contentData = await airtableGet(CONTENT_LIBRARY_TABLE, {
      filterByFormula: "AND(FIND('" + phone.phoneName + "', {content_label}), OR({platform_status_tiktok}='pending', {platform_status_instagram}='pending'))",
      'fields[]': 'content_label',
    });
    pendingCount = (contentData.records || []).length;
  } catch (e) {
    log.push(phone.phoneName + ': skip (content check error: ' + e.message + ')');
    continue;
  }

  if (pendingCount >= targetPending) {
    log.push(phone.phoneName + ': skip (' + pendingCount + '/' + targetPending + ' pending)');
    continue;
  }

  // --- 4. Check if any ready scenarios exist ---
  try {
    const scenarioData = await airtableGet(SCENARIOS_TABLE, {
      filterByFormula: "{status}='ready'",
      maxRecords: '1',
      'fields[]': 'status',
    });
    if ((scenarioData.records || []).length === 0) {
      log.push(phone.phoneName + ': skip (no ready scenarios)');
      continue;
    }
  } catch (e) {
    log.push(phone.phoneName + ': skip (scenario check error: ' + e.message + ')');
    continue;
  }

  // --- 5. Trigger production via internal webhook ---
  const hour = new Date().getHours();
  const timeOfDay = (hour >= 18 || hour < 6) ? 'night' : 'day';
  const payload = JSON.stringify({
    chatId: String(phone.chatId),
    scenarioName: '',
    timeOfDay,
    phoneName: phone.phoneName,
    isAuto: true,
  });

  try {
    const res = await fetch(WEBHOOK_BASE + WEBHOOK_PATH, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: payload,
    });
    if (res.ok) {
      log.push(phone.phoneName + ': TRIGGERED (' + pendingCount + '/' + targetPending + ' pending)');
      triggered++;
    } else {
      log.push(phone.phoneName + ': webhook error ' + res.status);
    }
  } catch (e) {
    log.push(phone.phoneName + ': webhook failed: ' + e.message);
  }
}

console.log('[auto-produce] ' + log.join(' | '));

return [{ json: { triggered, log, timestamp: new Date().toISOString() } }];

// NODE: Set Produce Context (merge node -- standardizes data from both trigger paths)
// Manual /produce: Telegram Trigger -> Parse Message -> Route Message -> this
// Auto-produce: Webhook -> this
// Downstream nodes reference $('Set Produce Context') instead of $('Parse Message')
//
// WIRING: Route Message (output 3) -> this | Auto Produce Webhook -> this -> Ack Produce

let chatId, scenarioName, timeOfDay, isAuto;

try {
  // Manual /produce path: Parse Message was executed in this run
  const pm = $('Parse Message').first().json;
  chatId = pm.chatId || '';
  scenarioName = pm.scenarioName || '';
  timeOfDay = pm.timeOfDay || 'day';
  isAuto = false;
} catch (e) {
  // Auto-produce path: data comes from webhook body via $input
  const input = $input.first().json;
  // Webhook v2 nests POST body under .body
  chatId = (input.body && input.body.chatId) || input.chatId || '';
  scenarioName = (input.body && input.body.scenarioName) || input.scenarioName || '';
  timeOfDay = (input.body && input.body.timeOfDay) || input.timeOfDay || 'day';
  isAuto = true;
}

return [{ json: { chatId, scenarioName, timeOfDay, isAuto } }];
